嘛，做科协的新生赛题目碰到了，这里记录一下思路。题目如下
PinballTime Limit: 2000/1000 MS (Java/Others)    Memory Limit: 262144/262144 K (Java/Others)Total Submission(s): 574    Accepted Submission(s): 249 Problem DescriptionThere is a slope on the 2D plane. The lowest point of the slope is at the origin. There is a small ball falling down above the slope. Your task is to find how many times the ball has been bounced on the slope.It&#x27;s guarantee that the ball will not reach the slope or ground or Y-axis with a distance of less than 1 from the origin. And the ball is elastic collision without energy loss. Gravity acceleration g=9.8m/s2. InputThere are multiple test cases. The first line of input contains an integer T (1 ≤ T ≤ 100), indicating the number of test cases.The first line of each test case contains four integers a, b, x, y (1 ≤ a, b, -x, y ≤ 100), indicate that the slope will pass through the point(-a, b), the initial position of the ball is (x, y). OutputOutput the answer.It&#x27;s guarantee that the answer will not exceed 50. Sample Input15 1 -5 3Sample Output2

 这题基本上是物理题，我看了大多数人的写法，大都是计算每次跳跃的距离然后判断。这题数据算是比较小的，这样当然要过也很容易，这里给出一个另一个思路。按照沿斜面方向和垂直斜面方向分解之后，沿斜面方向是典型的匀加速直线运动，直接求出距离然后计算总时间（二次方程求根），而每次跳跃的时间都是固定的，所以总时间再除以每次跳跃的时间，结果就出来了。这样非常快，时间空间复杂度都是常数，在vj平台上显示用时为0。
AC代码如下
#include&lt;iostream&gt;#include&lt;string&gt;#include&lt;vector&gt;#include&lt;algorithm&gt;#include&lt;map&gt;#include&lt;cmath&gt;#include&lt;iomanip&gt;#define ll long long#define ld long doubleusing namespace std;const ll tests[][4] = &#123;	&#123;5,1,-5,3&#125;,	&#123;99,17,-97,25&#125;&#125;;int main() &#123;	std::ios::sync_with_stdio(false);	cin.tie(NULL), cout.tie(NULL);	ll a, b, x, y;	const ld pi = acos(-1);	const ld pi2 = pi / 2;	const ld g = 9.8;	ld v0, ax, ay, vx, vy, tan0, sin0, cos0, h0, l0, tt, t0;	ll T;	cin &gt;&gt; T;	while (T--) &#123;		cin &gt;&gt; a &gt;&gt; b &gt;&gt; x &gt;&gt; y;				tan0 = (ld)b / a;		h0 = y - (-x)*tan0;		v0 = sqrt(2 * g*h0);		sin0 = sqrt(1 - 1 / (tan0*tan0 + 1));		cos0 = sqrt(1 / (tan0*tan0 + 1));		l0 = (-x) / cos0;//总长度		vx = v0 * sin0;		vy = v0 * cos0;		ax = g * sin0;		ay = g * cos0;		t0 = 2 * vy / ay;//单次跳跃时间				//解方程，1/2*ax*t*t+vx*t=l0		tt = (sqrt(vx*vx + 2 * ax*l0) - vx) / ax;		cout &lt;&lt; (ll)(tt / t0) + 1 &lt;&lt; endl;	&#125;	return 0;&#125;

题目查找长度为$n$的序列中第一个大于等于$k$的元素的位置，并将这个位置的值减去$k$，重复$m$次。
题解直接线段树。
首先建立线段树，每个节点保存区间内的最大值，从根节点递归下去即可，复杂度$O(n\log_2n)$。因为只需要单点更新，其实zkw线段树可能更适合，不过这里普通线段树就能过，就没必要了。
查找的过程也很简单，从根节点开始，如果当前节点的max小于$k$直接返回$-1$，如果当前节点是叶子节点就返回自己的索引，否则先找左儿子，左儿子如果是$-1$就返回右儿子，每次查询的复杂度是$O(\log_2n)$。我在自己笔记本上测试，$T=1,n=10^6,m=10^6$情况下的随机数据，基本压着1秒的线，太极限了。
代码AC代码有学长说这是主席树（持久化线段树），我也不知道是不是，照着OI-WiKi写的。
// @author: hzy#pragma G++ optimize(&quot;O3&quot;)#include &lt;algorithm&gt;#include &lt;cmath&gt;#include &lt;cstdio&gt;#include &lt;ctime&gt;#include &lt;cstring&gt;#include &lt;iostream&gt;#include &lt;queue&gt;#include &lt;map&gt;#include &lt;set&gt;#include &lt;string&gt;#include &lt;list&gt;#include &lt;forward_list&gt;#include &lt;stack&gt;#include &lt;unordered_set&gt;#include &lt;vector&gt;#include &lt;limits.h&gt;using namespace std;const long long MAX = 1e6 + 7;#define TREE_SUM 0#define TREE_MAX 1#define TREE_MIN 0//节点，包含区间和、最大值、最小值、区间左、区间右struct Node &#123;#if TREE_SUM    int sum;#endif#if TREE_MAX    long long max;#endif#if TREE_MIN    int min;#endif    int left, right;&#125;;Node tree[MAX * 4];long long a[MAX];class SegmentTree &#123;private:    int n;public:    SegmentTree(int _n) : n(_n * 4)/*, tree(_n * 4 + 1)*/ &#123;&#125;    SegmentTree(int _n, long long *a) : n(_n + 1)/*, tree(_n * 4 + 3)*/ &#123;        build(1, _n, 1, a);    &#125;    void build(int left, int right, int index, const long long *a) &#123;        auto &amp;node = tree[index];        if (left == right) &#123;            // 当前值#if TREE_SUM            tree[index].sum = a[left];#endif#if TREE_MAX            node.max = a[left];#endif#if TREE_MIN            tree[index].min = a[left];#endif            node.left = left;            node.right = left;            return;        &#125;        int mid = (left + right) / 2;        build(left, mid, index * 2, a);        build(mid + 1, right, index * 2 + 1, a);#if TREE_SUM        tree[index].sum = tree[index * 2].sum + tree[index * 2 + 1].sum;#endif#if TREE_MAX        node.max = max(tree[index * 2].max, tree[index * 2 + 1].max);#endif#if TREE_MIN        tree[index].min = min(tree[index * 2].min, tree[index * 2 + 1].min);#endif        node.left = left;        node.right = right;    &#125;#if TREE_SUM    // 求区间和    int querySum(int left, int right, int index = 1) &#123;        if (left &lt;= tree[index].left &amp;&amp; right &gt;= tree[index].right) &#123;            // 子集            return tree[index].sum;        &#125;        int ans = 0;        int mid = (tree[index].left + tree[index].right) / 2;        if (left &lt;= mid) &#123;            // [left,mid]与询问区间有交集，递归查询左儿子            ans += querySum(left, right, index * 2);        &#125;        if (right &gt; mid) &#123;            // [mid+1,right]与询问区间有交集，递归查询左儿子            ans += querySum(left, right, index * 2 + 1);        &#125;        return ans;    &#125;#endif#if TREE_MAX    // 求区间最大值    int queryMax(int left, int right, int index = 1) &#123;        if (left &lt;= tree[index].left &amp;&amp; right &gt;= tree[index].right) &#123;            // 子集            return tree[index].max;        &#125;        int leftAns = INT_MIN;        int rightAns = INT_MIN;        int mid = (tree[index].left + tree[index].right) / 2;        if (left &lt;= mid) &#123;            leftAns = queryMax(left, right, index * 2);        &#125;        if (right &gt; mid) &#123;            rightAns += queryMax(left, right, index * 2 + 1);        &#125;        return max(leftAns, rightAns);    &#125;#endif#if TREE_MIN    // 求区间最小值    int queryMin(int left, int right, int index = 1) &#123;        if (left &lt;= tree[index].left &amp;&amp; right &gt;= tree[index].right) &#123;            // 子集            return tree[index].min;        &#125;        int leftAns = INT_MAX;        int rightAns = INT_MAX;        int mid = (tree[index].left + tree[index].right) / 2;        if (left &lt;= mid) &#123;            leftAns = queryMin(left, right, index * 2);        &#125;        if (right &gt; mid) &#123;            rightAns = queryMin(left, right, index * 2 + 1);        &#125;        return min(leftAns, rightAns);    &#125;#endif#if TREE_SUM    // 更新父节点的区间和    void updateFatherSum(int treeIndex) &#123;        tree[treeIndex].sum = tree[treeIndex * 2].sum + tree[treeIndex * 2 + 1].sum;        if (treeIndex != 1) &#123;            updateFatherSum(treeIndex / 2);        &#125;    &#125;#endif#if TREE_MAX    void updateFatherMax(int treeIndex) &#123;        auto &amp;node = tree[treeIndex];        auto newMax = max(tree[treeIndex * 2].max, tree[treeIndex * 2 + 1].max);        if (newMax != node.max &amp;&amp; treeIndex != 1) &#123;            node.max = newMax;            updateFatherMax(treeIndex / 2);        &#125;    &#125;#endif    // 单点更新    void update(int index, long long value, int treeIndex = 1) &#123;        auto node = &amp;tree[treeIndex];        if (node-&gt;left == node-&gt;right) &#123;            //当前节点，更新#if TREE_SUM            tree[treeIndex].sum = value;            updateFatherSum(treeIndex);#endif#if TREE_MAX            node-&gt;max = value;            updateFatherMax(treeIndex / 2);#endif#if TREE_MIN            tree[treeIndex].min = value;#endif            return;        &#125;#if TREE_MAX        // 逐渐变小，应该不需要        // node-&gt;max = max(node-&gt;max, value);#endif#if TREE_MIN        tree[treeIndex].min = min(tree[treeIndex].min, value);#endif        int mid = (node-&gt;left + node-&gt;right) / 2;        if (index &lt;= mid) &#123;            update(index, value, treeIndex * 2);        &#125; else &#123;            update(index, value, treeIndex * 2 + 1);        &#125;    &#125;    // 查询第一个大于等于k的元素，通过max&gt;=k确定    int getAns(int left, int right, long long k, int treeIndex = 1) &#123;        auto &amp;node = tree[treeIndex];        if (node.max &lt; k) &#123;            // 别找了，就没有            return -1;        &#125;        if (node.left == node.right) &#123;            // 叶子，返回索引            a[node.left] -= k;            node.max -= k;            updateFatherMax(treeIndex / 2);            return node.left;        &#125;        int leftAns = -1, rightAns = -1;        if (node.left &gt;= left &amp;&amp; node.right &lt;= right) &#123;            // 此节点被包含在区间中            // 先找左边，是否有大于等于k的            leftAns = getAns(left, right, k, treeIndex * 2);            if (leftAns != -1) &#123;                return leftAns;            &#125;            return getAns(left, right, k, treeIndex * 2 + 1);        &#125;        // 有交集        int mid = (node.left + node.right) / 2;        if (left &lt;= mid) &#123;            leftAns = getAns(left, right, k, treeIndex * 2);            if (leftAns != -1) &#123;                return leftAns;            &#125;        &#125;        if (right &gt; mid) &#123;            return getAns(left, right, k, treeIndex * 2 + 1);        &#125;        return -1;    &#125;&#125;;auto st = SegmentTree(MAX);int main() &#123;    std::ios::sync_with_stdio(false);    std::cin.tie(0);    int t, n, m;    int l, r, k;    cin &gt;&gt; t;    while (t--) &#123;        cin &gt;&gt; n &gt;&gt; m;        for (int i = 1; i &lt;= n; i++) &#123;            cin &gt;&gt; a[i];        &#125;        // build tree        st.build(1, n, 1, a);        for (int i = 1; i &lt;= m; i++) &#123;            int idx = -1;            cin &gt;&gt; l &gt;&gt; r &gt;&gt; k;            idx = st.getAns(l, r, k);            cout &lt;&lt; idx &lt;&lt; &quot; &quot;;        &#125;    &#125;    return 0;&#125;

测试例生成（Python）#!/bin/env pythonimport randomdef v(t, n, m, max=1e9, filename=&#x27;in&#x27;):    t = int(t)    n = int(n)    m = int(m)    max = int(max)    step = t // 10    f = open(filename, &#x27;w&#x27;)    f.write(&quot;&#123;&#125;\r\n&quot;.format(t))    for i in range(t):        a = [str(random.randint(1, max)) for i in range(n)]        q = [&quot; &quot;.join([            str(random.randint(1, n // 2)),            str(random.randint(n // 2, n)),            str(random.randint(1, max))]) for i in range(m)]        f.write(&quot;&#123;&#125; &#123;&#125;\r\n&#123;&#125;\r\n&#123;&#125;\r\n&quot;.format(            n, m, &quot; &quot;.join(a), &quot;\r\n&quot;.join(q)        ))        if i % step == 0:            print(i)    f.close()

暴力验证// @author: hzy#pragma G++ optimize(&quot;O3&quot;)#include &lt;algorithm&gt;#include &lt;cmath&gt;#include &lt;cstdio&gt;#include &lt;cstring&gt;#include &lt;iostream&gt;#include &lt;queue&gt;#include &lt;map&gt;#include &lt;set&gt;#include &lt;string&gt;#include &lt;list&gt;#include &lt;forward_list&gt;#include &lt;stack&gt;#include &lt;unordered_set&gt;#include &lt;vector&gt;using namespace std;const long long MAX = 1e6 + 7;long long a[MAX];int main() &#123;    std::ios::sync_with_stdio(false);    std::cin.tie(0);    int t, n, m;    int l, r;    long long k;    cin &gt;&gt; t;    while (t--) &#123;        cin &gt;&gt; n &gt;&gt; m;        for (int i = 1; i &lt;= n; i++) &#123;            cin &gt;&gt; a[i];        &#125;        while (m--) &#123;            cin &gt;&gt; l &gt;&gt; r &gt;&gt; k;            // 暴力            for (; l &lt;= r; l++) &#123;                if (a[l] &gt;= k) &#123;                    break;                &#125;            &#125;            if (l &lt;= r) &#123;                cout &lt;&lt; l &lt;&lt; &quot; &quot;;                a[l] -= k;            &#125; else &#123;                cout &lt;&lt; -1 &lt;&lt; &quot; &quot;;            &#125;        &#125;    &#125;    return 0;&#125;

题目和UESTC-2430完全一致，数据量增大。
题解我觉得没写啥的必要了，和UESTC-2430完全一致，加上二进制优化就行。
代码AC代码这是debug之后了的，注意到打开了OPTIMIZE宏。
// @author: hzy//#pragma G++ optimize(&quot;O3&quot;)#include &lt;algorithm&gt;#include &lt;cmath&gt;#include &lt;cstdio&gt;#include &lt;ctime&gt;#include &lt;cstring&gt;#include &lt;iostream&gt;#include &lt;queue&gt;#include &lt;map&gt;#include &lt;set&gt;#include &lt;string&gt;#include &lt;list&gt;#include &lt;forward_list&gt;#include &lt;stack&gt;#include &lt;unordered_set&gt;#include &lt;vector&gt;#include &lt;limits.h&gt;#define DISPLAY_A 0#define OPTIMIZE 1using namespace std;class Thing &#123;public:    long long weight, value, number;&#125;;class Special &#123;public:    long long x, y, z;    long long getValue(long long weight) &#123;        if (weight == 0) &#123;            return max(0ll, z);        &#125;        return x * weight * weight + y * weight + z;    &#125;&#125;;Thing things[10007 * 15];int cnt = 0;Special specials[6];long long dp0[10007];long long dp[10007];const int pow2[] = &#123;1, 2, 4, 8, 16, 32, 64, 128, 256, 512, 1024, 2048, 4096, 8192, 16384&#125;;# if OPTIMIZE// 二进制优化int optimize() &#123;    int st = cnt;    int d = 0;    while (things[cnt].number &gt; pow2[d]) &#123;        things[cnt].number -= pow2[d];        // things[d + 1].number = 1;        things[cnt + d + 1].weight = things[cnt].weight * pow2[d];        things[cnt + d + 1].value = things[cnt].value * pow2[d];        d += 1;    &#125;    things[cnt].weight = things[cnt].weight * things[cnt].number;    things[cnt].value = things[cnt].value * things[cnt].number;    // things[cnt].number = 1;    cnt += d + 1;    return st;&#125;#endif#if DISPLAY_Aint sp[1007];#endifint main() &#123;    std::ios::sync_with_stdio(false);    std::cin.tie(0);    int n, m, c;    cin &gt;&gt; n &gt;&gt; m &gt;&gt; c;    for (int i = 1; i &lt;= n; i++) &#123;        cin &gt;&gt; things[cnt].weight &gt;&gt; things[cnt].value &gt;&gt; things[cnt].number;        // 多重背包#if OPTIMIZE        // 二进制优化        optimize();#else        for (int j = 1; j &lt;= c; j++) &#123;            // 不拿的情况(k=0)已经包含了            for (int k = 1; k &lt;= things[cnt].number; k++) &#123;                int weight = k * things[cnt].weight;                if (j &lt; weight) &#123;                    break;                &#125;                dp[j] = max(dp[j], dp0[j - weight] + things[cnt].value * k);            &#125;        &#125;        memcpy(dp0, dp, sizeof(long long) * (c + 3));#endif    &#125;    for (int i = 0; i &lt; cnt; i++) &#123;        for (int j = 1; j &lt;= c; j++) &#123;            if (j &lt; things[i].weight) &#123;                continue;            &#125;            dp[j] = max(dp0[j], dp0[j - things[i].weight] + things[i].value);        &#125;        memcpy(dp0, dp, sizeof(long long) * (c + 3));    &#125;    for (int i = 1; i &lt;= m; i++) &#123;        cin &gt;&gt; specials[i].x &gt;&gt; specials[i].y &gt;&gt; specials[i].z;        // 计算神奇物品        for (int j = 0; j &lt;= c; j++) &#123;            for (int k = 0; k &lt;= j; k++) &#123;#if DISPLAY_A                if (dp[j] &lt; dp0[j - k] + specials[i].getValue(k)) &#123;                    dp[j] = dp0[j - k] + specials[i].getValue(k);                    sp[i] = k;                &#125;#else                dp[j] = max(dp[j], dp0[j - k] + specials[i].getValue(k));#endif            &#125;        &#125;        memcpy(dp0, dp, sizeof(long long) * (c + 3));    &#125;#if DISPLAY_A    for (int i = 1; i &lt;= m; i++) &#123;        cout &lt;&lt; sp[i] &lt;&lt; &quot; &quot;;    &#125;    cout &lt;&lt; endl;#endif    cout &lt;&lt; dp[c] &lt;&lt; endl;    return 0;&#125;

