def G(n, m, c, max=1e3, filename=&#x27;/Volumes/RD/in&#x27;):    n = int(n)    m = int(m)    c = int(c)    f = open(filename, &#x27;w&#x27;)    f.write(&quot;&#123;&#125; &#123;&#125; &#123;&#125;\r\n&#123;&#125;\r\n&#123;&#125;&quot;.format(        n, m, c, &quot;\r\n&quot;.join([            &quot;&#123;&#125; &#123;&#125; &#123;&#125;&quot;.format(random.randint(1, max), random.randint(1, max), random.randint(1, max))            for i in range(n)        ]),        &quot;\r\n&quot;.join([            &quot;&#123;&#125; &#123;&#125; &#123;&#125;&quot;.format(random.randint(-max, max), random.randint(-max, max), random.randint(-max, max))            for i in range(m)        ])    ))    f.close()
